import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';

export default function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('/fees/dashboard').then(r => setStats(r.data)).catch(console.error).finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen" style={{ height: 300 }}><div className="spinner" /></div>;
  if (!stats) return <div className="alert alert-error">Failed to load dashboard</div>;

  const pieData = [
    { name: 'Collected', value: stats.summary.collected, color: '#10b981' },
    { name: 'Pending', value: stats.summary.pending, color: '#f59e0b' },
    { name: 'Overdue', value: stats.summary.overdue, color: '#ef4444' },
  ].filter(d => d.value > 0);

  const routeBarData = stats.routeStats.map(r => ({
    name: r.route?.routeNumber || 'N/A',
    collected: parseFloat(r.dataValues?.totalCollected || 0),
    students: parseInt(r.dataValues?.count || 0),
  }));

  const fmt = (n) => `₹${Number(n).toLocaleString('en-IN')}`;

  return (
    <div>
      <div className="stats-grid">
        <div className="stat-card blue">
          <div className="stat-label">Total Students</div>
          <div className="stat-value">{stats.totalStudents}</div>
          <div className="stat-sub">Active enrollments</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Total Routes</div>
          <div className="stat-value">{stats.totalRoutes}</div>
          <div className="stat-sub">Active bus routes</div>
        </div>
        <div className="stat-card green">
          <div className="stat-label">Fees Collected</div>
          <div className="stat-value" style={{ fontSize: 20 }}>{fmt(stats.summary.collected)}</div>
          <div className="stat-sub">{stats.paidCount} payments this month</div>
        </div>
        <div className="stat-card yellow">
          <div className="stat-label">Fees Pending</div>
          <div className="stat-value" style={{ fontSize: 20 }}>{fmt(stats.summary.pending)}</div>
          <div className="stat-sub">{stats.pendingCount} students pending</div>
        </div>
        {stats.summary.overdue > 0 && (
          <div className="stat-card red">
            <div className="stat-label">Overdue Fees</div>
            <div className="stat-value" style={{ fontSize: 20 }}>{fmt(stats.summary.overdue)}</div>
            <div className="stat-sub">Requires attention</div>
          </div>
        )}
      </div>

      <div className="charts-grid">
        {pieData.length > 0 && (
          <div className="card">
            <div className="card-header"><h3 className="card-title">📊 Fee Collection Status</h3><span style={{ fontSize: 12, color: 'var(--text-muted)' }}>{stats.currentMonth}</span></div>
            <ResponsiveContainer width="100%" height={240}>
              <PieChart>
                <Pie data={pieData} cx="50%" cy="50%" innerRadius={60} outerRadius={90} paddingAngle={4} dataKey="value">
                  {pieData.map((e, i) => <Cell key={i} fill={e.color} />)}
                </Pie>
                <Tooltip formatter={(v) => fmt(v)} />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
        )}

        {routeBarData.length > 0 && (
          <div className="card">
            <div className="card-header"><h3 className="card-title">🗺️ Collection by Route</h3></div>
            <ResponsiveContainer width="100%" height={240}>
              <BarChart data={routeBarData} margin={{ top: 5, right: 10, bottom: 5, left: 10 }}>
                <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                <YAxis tick={{ fontSize: 12 }} />
                <Tooltip formatter={(v) => fmt(v)} />
                <Bar dataKey="collected" fill="#1e40af" radius={[4, 4, 0, 0]} name="Collected" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        )}
      </div>

      <div className="card" style={{ marginTop: 20 }}>
        <div className="card-header">
          <h3 className="card-title">🚌 Route Summary</h3>
        </div>
        {routeBarData.length === 0 ? (
          <div className="empty-state"><span className="icon">📭</span><p>No fee data for this month yet</p></div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead><tr><th>Route</th><th>Students Paid</th><th>Amount Collected</th></tr></thead>
              <tbody>
                {routeBarData.map((r, i) => (
                  <tr key={i}>
                    <td><strong>{r.name}</strong></td>
                    <td>{r.students}</td>
                    <td><strong style={{ color: 'var(--success)' }}>{fmt(r.collected)}</strong></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
